trigger.body:
  v_Processed VARCHAR(60) ;
  v_C_ORDER_ID VARCHAR2(32) ;
  v_CostCenterID  VARCHAR2(32) ;
  v_Docaction VARCHAR(60) ;
  v_Docstatus VARCHAR(60);
  v_BaseDocType VARCHAR(60);
  v_DocumentNo C_ORDER.DocumentNO%TYPE;
  v_IsSOTrx CHAR(1);
  v_Message VARCHAR2(2000):='';
  v_QTYVARIABLE CHAR(1);
  v_productname m_product.name%TYPE;
  v_isgeneric   CHAR(1);

  v_Count NUMBER ; --OBTG:NUMBER-

BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

	IF INSERTING THEN
		v_C_ORDER_ID:=:NEW.C_ORDERLINE_ID;
	ELSE
		v_C_ORDER_ID:=:OLD.C_ORDERLINE_ID;
	END IF;

	IF (INSERTING OR UPDATING) THEN

		SELECT
		COALESCE((SELECT  COUNT(*)
		FROM C_ORDERLINE COL
		WHERE col.C_ORDERLINE_ID=v_C_ORDER_ID
		),0)
		INTO v_Count
		FROM DUAL;



		IF (v_Count>0) THEN 


			SELECT
			COALESCE((SELECT ISSOTRX
			FROM C_ORDER CO
			JOIN C_ORDERLINE COL ON CO.C_ORDER_ID = COL.C_ORDER_ID
			WHERE coL.C_ORDERLINE_ID =v_C_ORDER_ID),'N')
			INTO v_IsSOTrx
			FROM DUAL;


			SELECT
			COALESCE((SELECT docbasetype
			FROM C_ORDER CO
			JOIN C_ORDERLINE COL ON CO.C_ORDER_ID = COL.C_ORDER_ID
			JOIN C_DOCTYPE CD ON CD.C_DOCTYPE_ID = CO.C_DOCTYPE_ID
			WHERE coL.C_ORDERLINE_ID =v_C_ORDER_ID),'N')
			INTO v_BaseDocType
			FROM DUAL;

			IF (v_IsSOTrx ='Y' AND v_BaseDocType = 'SOO') THEN

				SELECT COALESCE(TO_CHAR((select C_COSTCENTER_ID from C_ORDERLINE COL where coL.C_ORDERLINE_ID =v_C_ORDER_ID)),TO_CHAR('ND'))
				INTO v_CostCenterID
				FROM DUAL;

				IF (v_CostCenterID<>'ND') THEN
					:new.c_costcenter_id:=v_CostCenterID;
				END IF;

			END IF;
		END IF;

	END IF;


END SSTPC_COPY_CC_MINOUT_TRG
